const HTML = "<!doctype html>\n<html lang=\"es\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <meta name=\"theme-color\" content=\"#071b24\">\n  <link rel=\"icon\" href=\"data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 64 64'%3E%3Crect width='64' height='64' rx='16' fill='%2308232d'/%3E%3Cpath d='M32 10C24 23 16 31 16 41a16 16 0 0 0 32 0c0-10-8-18-16-31Z' fill='none' stroke='%2339e1d0' stroke-width='4'/%3E%3C/svg%3E\">\n  <title>PAE HydroWatch | Monitoreo hidrológico</title>\n  <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n  <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n  <link href=\"https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&family=Space+Grotesk:wght@500;600;700&display=swap\" rel=\"stylesheet\">\n  <script src=\"https://cdn.jsdelivr.net/npm/echarts@5.5.1/dist/echarts.min.js\"></script>\n  <style>:root{--bg:#06151c;--panel:rgba(11,35,45,.82);--panel-2:#0d2a35;--line:rgba(151,210,222,.13);--text:#eefaff;--muted:#88a8b3;--cyan:#39e1d0;--blue:#58a6ff;--orange:#ffad5b;--violet:#a984ff;--green:#6be6a4;--red:#ff6b71;--radius:22px;--shadow:0 22px 60px rgba(0,0,0,.22)}\n*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;background:radial-gradient(circle at 62% -10%,#103b47 0,transparent 30%),var(--bg);color:var(--text);font-family:Manrope,system-ui,sans-serif;min-height:100vh}.ambient{position:fixed;border-radius:50%;filter:blur(100px);opacity:.13;pointer-events:none}.ambient-one{width:420px;height:420px;background:var(--cyan);right:-160px;top:20%}.ambient-two{width:300px;height:300px;background:#1978ff;left:18%;bottom:-180px}.sidebar{position:fixed;inset:0 auto 0 0;width:236px;padding:30px 24px 24px;border-right:1px solid var(--line);background:rgba(4,18,24,.88);backdrop-filter:blur(18px);z-index:5;display:flex;flex-direction:column}.brand{display:flex;gap:12px;align-items:center;color:var(--text);text-decoration:none}.brand-mark{width:44px;height:44px;border:1px solid rgba(57,225,208,.35);border-radius:14px;display:grid;place-items:center;background:rgba(57,225,208,.08)}.brand svg{width:28px;fill:none;stroke:var(--cyan);stroke-width:2}.brand strong{font:700 20px/1 Space Grotesk}.brand small{display:block;color:var(--muted);font-size:11px;letter-spacing:.14em;margin-top:5px}.sidebar nav{display:grid;gap:8px;margin-top:58px}.sidebar nav a{color:#71929e;text-decoration:none;padding:13px 12px;border-radius:12px;font-size:13px;font-weight:600;transition:.2s}.sidebar nav a span{font:500 10px Space Grotesk;margin-right:12px;color:#456772}.sidebar nav a:hover,.sidebar nav a.active{background:linear-gradient(90deg,rgba(57,225,208,.13),transparent);color:var(--text)}.sidebar nav a.active{box-shadow:inset 2px 0 var(--cyan)}.side-card{margin-top:auto;padding:16px;border:1px solid var(--line);border-radius:16px;background:rgba(15,46,57,.55)}.eyebrow{display:block;color:#68919d;font:700 9px/1.2 Space Grotesk;letter-spacing:.18em}.side-card strong{display:block;margin:8px 0 12px;font:600 18px Space Grotesk}.connection{display:flex;align-items:center;gap:8px;color:var(--muted);font-size:10px}.connection i{width:7px;height:7px;border-radius:50%;background:#f0a94b;box-shadow:0 0 10px #f0a94b}.connection i.online{background:var(--green);box-shadow:0 0 12px var(--green)}.connection i.offline{background:var(--red);box-shadow:0 0 12px var(--red)}.settings-button{margin-top:10px;width:100%;background:none;border:0;color:#70929e;text-align:left;padding:9px 3px;font:600 10px Manrope;cursor:pointer}.side-foot{font-size:10px;color:#53727c;line-height:1.5;margin:18px 3px 0}.side-foot span{color:#38565f}main{margin-left:236px;padding:34px 42px 26px;max-width:1900px}.topbar{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:28px}.topbar h1{font:600 27px/1.2 Space Grotesk;margin:8px 0 0;letter-spacing:-.03em}.top-actions{display:flex;align-items:center;gap:14px}.range-control{font-size:9px;color:var(--muted);text-transform:uppercase;letter-spacing:.12em}.range-control select{display:block;margin-top:5px;background:#0b2631;color:var(--text);border:1px solid var(--line);border-radius:9px;padding:8px 28px 8px 10px}.icon-button{width:39px;height:39px;border:1px solid var(--line);border-radius:12px;background:#0b2631;color:var(--cyan);font-size:22px;cursor:pointer}.icon-button.loading{animation:spin 1s linear infinite}.updated{border-left:1px solid var(--line);padding-left:14px}.updated span{display:block;color:var(--muted);font-size:9px}.updated strong{font:600 12px Space Grotesk}@keyframes spin{to{transform:rotate(360deg)}}.panel{background:linear-gradient(145deg,rgba(14,47,59,.88),rgba(7,27,36,.88));border:1px solid var(--line);box-shadow:var(--shadow);border-radius:var(--radius)}.hero{min-height:330px;display:grid;grid-template-columns:1.4fr .72fr .52fr;gap:30px;align-items:center;padding:38px 42px;overflow:hidden;position:relative;background:linear-gradient(110deg,rgba(10,42,52,.95),rgba(7,29,38,.88)),radial-gradient(circle at 70% 50%,rgba(57,225,208,.16),transparent 36%)}.hero:after{content:\"\";position:absolute;width:360px;height:360px;border:1px solid rgba(57,225,208,.09);border-radius:50%;right:14%;top:-130px;box-shadow:0 0 0 38px rgba(57,225,208,.025),0 0 0 78px rgba(57,225,208,.018)}.hero-copy,.level-gauge,.hero-status{position:relative;z-index:1}.live-pill{display:inline-flex;align-items:center;gap:7px;padding:7px 10px;border:1px solid rgba(107,230,164,.2);border-radius:20px;color:var(--green);font:700 8px Space Grotesk;letter-spacing:.14em;background:rgba(107,230,164,.06)}.live-pill span{width:6px;height:6px;border-radius:50%;background:var(--green);box-shadow:0 0 9px var(--green);animation:pulse 2s infinite}@keyframes pulse{50%{opacity:.35}}.hero-kicker{font:700 10px Space Grotesk;letter-spacing:.18em;color:#638a96;margin:25px 0 8px}.hero h2{font:600 clamp(28px,3vw,45px)/1.06 Space Grotesk;letter-spacing:-.045em;margin:0}.hero h2 em{font-style:normal;color:var(--cyan)}.hero-copy>p:not(.hero-kicker){max-width:610px;color:#8fb0ba;line-height:1.75;font-size:13px}.hero-meta{display:flex;gap:24px;color:#648793;font-size:10px;margin-top:20px}.level-gauge{text-align:center}.gauge-ring{width:176px;height:176px;margin:auto;border-radius:50%;display:grid;place-items:center;background:conic-gradient(var(--cyan) 0 72%,rgba(68,115,125,.18) 72%);position:relative;filter:drop-shadow(0 0 25px rgba(57,225,208,.12))}.gauge-ring:before{content:\"\";position:absolute;inset:8px;border-radius:50%;background:#0a2833}.gauge-ring div{z-index:1}.gauge-ring span{font:600 44px/1 Space Grotesk}.gauge-ring small{font:600 13px Space Grotesk;color:var(--cyan);margin-left:4px}.gauge-ring b{display:block;margin-top:9px;color:#628894;font:700 8px Space Grotesk;letter-spacing:.13em}.level-gauge p{color:#6d929d;font-size:10px}.hero-status{border-left:1px solid var(--line);padding-left:28px}.hero-status span{color:#668995;font:700 8px Space Grotesk;letter-spacing:.15em}.hero-status strong{display:block;color:var(--green);font:600 25px Space Grotesk;margin:10px 0 7px}.hero-status small{color:#7496a1;line-height:1.5}.kpi-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:14px;margin:16px 0}.kpi{display:flex;gap:14px;align-items:center;min-width:0;padding:18px 17px;background:rgba(9,34,44,.7);border:1px solid var(--line);border-radius:17px}.kpi-icon{width:40px;height:40px;flex:0 0 40px;display:grid;place-items:center;border-radius:13px;font-size:18px}.kpi-icon.cyan{color:var(--cyan);background:rgba(57,225,208,.09)}.kpi-icon.blue{color:var(--blue);background:rgba(88,166,255,.09)}.kpi-icon.orange{color:var(--orange);background:rgba(255,173,91,.09)}.kpi-icon.violet{color:var(--violet);background:rgba(169,132,255,.09)}.kpi-icon.green{color:var(--green);background:rgba(107,230,164,.09)}.kpi span{display:block;color:#6f929d;font-size:9px}.kpi strong{display:block;font:600 21px Space Grotesk;margin:3px 0}.kpi small{display:block;color:#4f717b;font-size:8px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.chart-grid{display:grid;grid-template-columns:1.6fr .82fr;gap:16px;margin-top:16px}.chart-grid.two{grid-template-columns:1fr 1fr}.chart-card,.insight-card{padding:23px 24px}.chart-card.wide{min-width:0}.card-head{display:flex;justify-content:space-between;align-items:flex-start;gap:16px}.card-head h3,.insight-card h3,.records h3{font:600 17px Space Grotesk;margin:6px 0 0}.unit{color:#567984;font-size:8px;border:1px solid var(--line);padding:6px 8px;border-radius:8px}.chart{height:265px;margin-top:5px}.insight-card{background:linear-gradient(155deg,rgba(20,64,72,.92),rgba(8,31,39,.94))}.insight-card h3{font-size:23px;line-height:1.25;margin:25px 0 12px}.insight-card p{color:#81a2ac;font-size:11px;line-height:1.7;min-height:62px}.insight-metric{display:flex;justify-content:space-between;padding:13px 0;border-top:1px solid var(--line);font-size:10px;color:#658993}.insight-metric strong{font:600 15px Space Grotesk;color:var(--text)}.records{padding:24px;margin-top:16px}.secondary-button,.primary-button{border-radius:10px;padding:10px 13px;font:600 10px Manrope;cursor:pointer}.secondary-button{border:1px solid var(--line);background:rgba(22,58,69,.6);color:#a3c0c8}.primary-button{border:0;background:var(--cyan);color:#062029}.table-wrap{overflow:auto;margin-top:18px;border:1px solid var(--line);border-radius:14px}table{width:100%;border-collapse:collapse;font-size:10px}th{text-align:left;color:#618590;background:rgba(18,54,65,.75);font:700 8px Space Grotesk;letter-spacing:.08em;padding:12px;white-space:nowrap}td{padding:12px;color:#8fadb6;border-top:1px solid rgba(151,210,222,.08);white-space:nowrap}tbody tr:hover{background:rgba(57,225,208,.035)}.status-chip{display:inline-flex;padding:5px 8px;border-radius:15px;font:700 8px Space Grotesk}.status-0{color:var(--green);background:rgba(107,230,164,.1)}.status-1{color:#e8d164;background:rgba(232,209,100,.1)}.status-2{color:var(--orange);background:rgba(255,173,91,.1)}.status-3{color:var(--red);background:rgba(255,107,113,.1)}.empty{text-align:center;padding:35px;color:#567984}footer{text-align:center;color:#3f626d;font-size:9px;padding:28px}footer span{margin:0 7px}dialog{width:min(460px,calc(100% - 30px));border:1px solid var(--line);border-radius:20px;background:#0a2530;color:var(--text);padding:0;box-shadow:0 35px 100px #0008}dialog::backdrop{background:rgba(1,11,15,.72);backdrop-filter:blur(7px)}dialog form{padding:25px}.dialog-head{display:flex;justify-content:space-between;margin-bottom:22px}.dialog-head h3{font:600 21px Space Grotesk;margin:7px 0}.dialog-head button{border:0;background:none;color:#7799a4;font-size:25px;cursor:pointer}dialog label{display:block;color:#91adb5;font-size:10px;margin-top:15px}dialog label span{color:#54747e}dialog input{display:block;width:100%;margin-top:7px;padding:12px;border-radius:10px;border:1px solid var(--line);background:#071c24;color:var(--text);outline:none}.privacy-note{color:#557680;font-size:9px;line-height:1.5}.dialog-actions{display:flex;justify-content:flex-end;gap:8px;margin-top:20px}#toast{position:fixed;right:25px;bottom:25px;z-index:20;background:#133943;color:#c5e7ed;border:1px solid var(--line);padding:12px 16px;border-radius:12px;font-size:10px;box-shadow:var(--shadow);opacity:0;transform:translateY(12px);pointer-events:none;transition:.25s}#toast.show{opacity:1;transform:none}\n@media(max-width:1100px){.sidebar{width:190px}.sidebar nav a span{display:none}main{margin-left:190px;padding:28px}.hero{grid-template-columns:1fr .65fr}.hero-status{grid-column:1/-1;border-left:0;border-top:1px solid var(--line);padding:18px 0 0}.kpi-grid{grid-template-columns:repeat(3,1fr)}.chart-grid{grid-template-columns:1fr 1fr}}\n@media(max-width:760px){.sidebar{position:static;width:auto;height:auto;padding:17px 20px;flex-direction:row;align-items:center}.sidebar nav,.side-card,.settings-button,.side-foot{display:none}main{margin:0;padding:20px 14px}.topbar{align-items:flex-start}.topbar h1{font-size:22px}.range-control,.updated{display:none}.hero{grid-template-columns:1fr;padding:28px 23px}.level-gauge{margin-top:8px}.hero-status{grid-column:auto}.kpi-grid{grid-template-columns:1fr 1fr}.chart-grid,.chart-grid.two{grid-template-columns:1fr}.chart{height:240px}}\n@media(max-width:440px){.kpi-grid{grid-template-columns:1fr}.hero h2{font-size:31px}.gauge-ring{width:150px;height:150px}.top-actions{gap:8px}}\n.mobile-settings{display:none;font-size:15px}\n@media(max-width:760px){.topbar{align-items:flex-start;flex-direction:column;gap:12px}.range-control{display:block}.mobile-settings{display:grid;place-items:center}}\n</style>\n</head>\n<body>\n  <div class=\"ambient ambient-one\"></div><div class=\"ambient ambient-two\"></div>\n  <aside class=\"sidebar\">\n    <a class=\"brand\" href=\"#resumen\" aria-label=\"Ir al resumen\">\n      <span class=\"brand-mark\" aria-hidden=\"true\"><svg viewBox=\"0 0 48 48\"><path d=\"M24 5C18 15 10 23 10 31a14 14 0 0 0 28 0C38 23 30 15 24 5Z\"/><path d=\"M16 32c4 3 12 4 19-2\"/></svg></span>\n      <span><strong>PAE</strong><small>HydroWatch</small></span>\n    </a>\n    <nav aria-label=\"Navegación principal\">\n      <a class=\"active\" href=\"#resumen\"><span>01</span>Resumen</a>\n      <a href=\"#tendencias\"><span>02</span>Tendencias</a>\n      <a href=\"#ambiente\"><span>03</span>Ambiente</a>\n      <a href=\"#registros\"><span>04</span>Registros</a>\n    </nav>\n    <div class=\"side-card\">\n      <span class=\"eyebrow\">CANAL IOT</span>\n      <strong>#3420787</strong>\n      <div class=\"connection\"><i id=\"connectionDot\"></i><span id=\"connectionLabel\">Conectando…</span></div>\n    </div>\n    <button class=\"settings-button\" id=\"openSettings\" type=\"button\">⚙ Configurar conexión</button>\n    <p class=\"side-foot\">Proyecto hidrológico<br><span>ThingSpeak · Tiempo real</span></p>\n  </aside>\n\n  <main>\n    <header class=\"topbar\">\n      <div>\n        <span class=\"eyebrow\">CENTRO DE MONITOREO</span>\n        <h1>Lectura clara. Decisiones a tiempo.</h1>\n      </div>\n      <div class=\"top-actions\">\n        <label class=\"range-control\">Ventana\n          <select id=\"rangeSelect\"><option value=\"50\">50 lecturas</option><option value=\"100\" selected>100 lecturas</option><option value=\"250\">250 lecturas</option><option value=\"500\">500 lecturas</option></select>\n        </label>\n        <button id=\"refreshButton\" class=\"icon-button\" type=\"button\" aria-label=\"Actualizar datos\">↻</button>\n        <button id=\"mobileSettings\" class=\"icon-button mobile-settings\" type=\"button\" aria-label=\"Configurar conexión\">⚙</button>\n        <div class=\"updated\"><span>Última actualización</span><strong id=\"lastUpdated\">—</strong></div>\n      </div>\n    </header>\n\n    <section id=\"resumen\" class=\"hero panel\">\n      <div class=\"hero-copy\">\n        <div class=\"live-pill\"><span></span> TELEMETRÍA EN VIVO</div>\n        <p class=\"hero-kicker\">SISTEMA HIDROLÓGICO INTELIGENTE</p>\n        <h2>El agua cuenta una historia.<br><em>Ahora podemos verla.</em></h2>\n        <p>Seguimiento continuo del nivel, condiciones ambientales y comportamiento predictivo para anticipar escenarios de riesgo.</p>\n        <div class=\"hero-meta\"><span>📍 Estación PAE</span><span>◷ Muestreo IoT</span></div>\n      </div>\n      <div class=\"level-gauge\">\n        <div class=\"gauge-ring\"><div><span id=\"levelValue\">—</span><small>m</small><b>NIVEL ACTUAL</b></div></div>\n        <p id=\"levelTrend\">Esperando lectura…</p>\n      </div>\n      <div class=\"hero-status\"><span>ESTADO DEL SISTEMA</span><strong id=\"systemStatus\">Sin datos</strong><small id=\"statusDescription\">Conectando con ThingSpeak</small></div>\n    </section>\n\n    <section class=\"kpi-grid\" aria-label=\"Indicadores actuales\">\n      <article class=\"kpi\"><div class=\"kpi-icon cyan\">≈</div><div><span>Nivel</span><strong id=\"kpiLevel\">—</strong><small id=\"kpiLevelDelta\">Sin comparación</small></div></article>\n      <article class=\"kpi\"><div class=\"kpi-icon blue\">☂</div><div><span>Lluvia</span><strong id=\"kpiRain\">—</strong><small id=\"kpiRainState\">Estado del sensor</small></div></article>\n      <article class=\"kpi\"><div class=\"kpi-icon orange\">☼</div><div><span>Temperatura</span><strong id=\"kpiTemp\">—</strong><small>Ambiente</small></div></article>\n      <article class=\"kpi\"><div class=\"kpi-icon violet\">◌</div><div><span>Humedad</span><strong id=\"kpiHum\">—</strong><small>Humedad relativa</small></div></article>\n      <article class=\"kpi\"><div class=\"kpi-icon green\">➜</div><div><span>Velocidad</span><strong id=\"kpiSpeed\">—</strong><small>Variación del nivel</small></div></article>\n    </section>\n\n    <section id=\"tendencias\" class=\"chart-grid\">\n      <article class=\"panel chart-card wide\"><div class=\"card-head\"><div><span class=\"eyebrow\">COMPORTAMIENTO</span><h3>Nivel observado</h3></div><span class=\"unit\">metros</span></div><div id=\"levelChart\" class=\"chart\"></div></article>\n      <article class=\"panel insight-card\"><span class=\"eyebrow\">LECTURA CLAVE</span><h3 id=\"insightTitle\">Analizando la serie…</h3><p id=\"insightText\">La interpretación se actualizará con la última ventana de lecturas.</p><div class=\"insight-metric\"><span>Promedio</span><strong id=\"avgLevel\">—</strong></div><div class=\"insight-metric\"><span>Máximo</span><strong id=\"maxLevel\">—</strong></div></article>\n      <article class=\"panel chart-card\"><div class=\"card-head\"><div><span class=\"eyebrow\">MODELO</span><h3>Nivel de predicción</h3></div><span class=\"unit\">escala independiente</span></div><div id=\"predictionChart\" class=\"chart\"></div></article>\n      <article class=\"panel chart-card\"><div class=\"card-head\"><div><span class=\"eyebrow\">DINÁMICA</span><h3>Velocidad</h3></div><span class=\"unit\">variación</span></div><div id=\"speedChart\" class=\"chart\"></div></article>\n    </section>\n\n    <section id=\"ambiente\" class=\"chart-grid two\">\n      <article class=\"panel chart-card\"><div class=\"card-head\"><div><span class=\"eyebrow\">ENTORNO</span><h3>Temperatura y humedad</h3></div><span class=\"unit\">doble escala</span></div><div id=\"climateChart\" class=\"chart\"></div></article>\n      <article class=\"panel chart-card\"><div class=\"card-head\"><div><span class=\"eyebrow\">EVENTOS</span><h3>Lluvia y estados</h3></div><span class=\"unit\">por lectura</span></div><div id=\"eventsChart\" class=\"chart\"></div></article>\n    </section>\n\n    <section id=\"registros\" class=\"panel records\">\n      <div class=\"card-head\"><div><span class=\"eyebrow\">TRAZABILIDAD</span><h3>Lecturas recientes</h3></div><button id=\"downloadCsv\" class=\"secondary-button\" type=\"button\">↓ Exportar CSV</button></div>\n      <div class=\"table-wrap\"><table><thead><tr><th>Fecha y hora</th><th>Nivel</th><th>Lluvia</th><th>Temperatura</th><th>Humedad</th><th>Velocidad</th><th>Predicción</th><th>Estado</th></tr></thead><tbody id=\"recordsBody\"><tr><td colspan=\"8\" class=\"empty\">Cargando lecturas…</td></tr></tbody></table></div>\n    </section>\n    <footer>PAE HydroWatch <span>•</span> Datos proporcionados por ThingSpeak <span>•</span> <span id=\"entryCount\">0 lecturas</span></footer>\n  </main>\n\n  <dialog id=\"settingsDialog\">\n    <form method=\"dialog\" id=\"settingsForm\">\n      <div class=\"dialog-head\"><div><span class=\"eyebrow\">CONEXIÓN</span><h3>Configurar ThingSpeak</h3></div><button value=\"cancel\" aria-label=\"Cerrar\">×</button></div>\n      <label>ID del canal<input id=\"channelInput\" inputmode=\"numeric\" value=\"3420787\" required></label>\n      <label>Read API Key <span>(opcional para canal público)</span><input id=\"apiKeyInput\" type=\"password\" autocomplete=\"off\" placeholder=\"Se conserva solo durante esta sesión\"></label>\n      <p class=\"privacy-note\">La clave no se escribe en el código ni se guarda de forma permanente.</p>\n      <div class=\"dialog-actions\"><button value=\"cancel\" class=\"secondary-button\">Cancelar</button><button id=\"saveSettings\" value=\"default\" class=\"primary-button\">Conectar</button></div>\n    </form>\n  </dialog>\n  <div id=\"toast\" role=\"status\" aria-live=\"polite\"></div>\n  <script type=\"module\">const DEFAULT_CHANNEL = \"3420787\";\nconst STATUS = {\n  0: { label: \"Normal\", description: \"Condiciones estables\", className: \"status-0\", color: \"#6be6a4\" },\n  1: { label: \"Preventivo\", description: \"Requiere observación\", className: \"status-1\", color: \"#e8d164\" },\n  2: { label: \"Alerta\", description: \"Variación relevante\", className: \"status-2\", color: \"#ffad5b\" },\n  3: { label: \"Crítico\", description: \"Atención inmediata\", className: \"status-3\", color: \"#ff6b71\" }\n};\nconst $ = (id) => document.getElementById(id);\nlet feeds = [];\nlet charts = [];\nlet refreshTimer;\n\nexport function normalizeFeed(feed) {\n  const number = (value) => value === null || value === \"\" || Number.isNaN(Number(value)) ? null : Number(value);\n  return { date: new Date(feed.created_at), entryId: Number(feed.entry_id), level: number(feed.field1), rain: number(feed.field2), temp: number(feed.field3), hum: number(feed.field4), speed: number(feed.field5), prediction: number(feed.field6), status: number(feed.field7) };\n}\nexport function buildFeedUrl(channel, results, apiKey = \"\") {\n  const url = new URL(`https://api.thingspeak.com/channels/${encodeURIComponent(channel)}/feeds.json`);\n  url.searchParams.set(\"results\", String(results));\n  if (apiKey.trim()) url.searchParams.set(\"api_key\", apiKey.trim());\n  return url.toString();\n}\nexport function stats(values) {\n  const clean = values.filter(Number.isFinite);\n  if (!clean.length) return { avg: null, min: null, max: null };\n  return { avg: clean.reduce((a, b) => a + b, 0) / clean.length, min: Math.min(...clean), max: Math.max(...clean) };\n}\nconst fmt = (value, digits = 2) => Number.isFinite(value) ? value.toLocaleString(\"es-PE\", { minimumFractionDigits: digits, maximumFractionDigits: digits }) : \"—\";\nconst fmtDate = (date, compact = false) => new Intl.DateTimeFormat(\"es-PE\", compact ? { day: \"2-digit\", month: \"2-digit\", hour: \"2-digit\", minute: \"2-digit\" } : { dateStyle: \"short\", timeStyle: \"medium\" }).format(date);\nconst currentConfig = () => ({ channel: sessionStorage.getItem(\"tsChannel\") || DEFAULT_CHANNEL, apiKey: sessionStorage.getItem(\"tsReadKey\") || \"\", results: Number($(\"rangeSelect\")?.value || 100) });\n\nasync function loadData(showFeedback = false) {\n  const button = $(\"refreshButton\");\n  button?.classList.add(\"loading\");\n  try {\n    const { channel, apiKey, results } = currentConfig();\n    const response = await fetch(buildFeedUrl(channel, results, apiKey), { cache: \"no-store\" });\n    if (!response.ok) throw new Error(`ThingSpeak respondió ${response.status}`);\n    const payload = await response.json();\n    feeds = payload.feeds.map(normalizeFeed).filter((row) => !Number.isNaN(row.date.getTime()));\n    if (!feeds.length) throw new Error(\"El canal no contiene lecturas en la ventana seleccionada\");\n    render(payload.channel);\n    setConnection(true, apiKey ? \"Privado · conectado\" : \"Público · conectado\");\n    if (showFeedback) toast(\"Datos actualizados correctamente\");\n  } catch (error) {\n    setConnection(false, \"Sin conexión\");\n    toast(error.message || \"No fue posible consultar ThingSpeak\", true);\n  } finally { button?.classList.remove(\"loading\"); }\n}\n\nfunction setConnection(online, label) { $(\"connectionDot\").className = online ? \"online\" : \"offline\"; $(\"connectionLabel\").textContent = label; }\nfunction render(channel) {\n  const last = feeds.at(-1), previous = feeds.at(-2), state = STATUS[last.status] || { label: `Código ${last.status ?? \"—\"}`, description: \"Estado sin catalogar\", color: \"#88a8b3\" };\n  const delta = previous && Number.isFinite(last.level) && Number.isFinite(previous.level) ? last.level - previous.level : null;\n  $(\"levelValue\").textContent = fmt(last.level);\n  $(\"levelTrend\").textContent = delta === null ? \"Sin lectura anterior\" : `${delta >= 0 ? \"↑\" : \"↓\"} ${fmt(Math.abs(delta))} m respecto a la lectura anterior`;\n  $(\"systemStatus\").textContent = state.label; $(\"systemStatus\").style.color = state.color; $(\"statusDescription\").textContent = state.description;\n  $(\"kpiLevel\").textContent = `${fmt(last.level)} m`; $(\"kpiLevelDelta\").textContent = delta === null ? \"Sin comparación\" : `${delta >= 0 ? \"+\" : \"\"}${fmt(delta)} m en la última lectura`;\n  $(\"kpiRain\").textContent = last.rain > 0 ? `${fmt(last.rain)} mm` : \"Sin lluvia\"; $(\"kpiRainState\").textContent = last.rain > 0 ? \"Evento detectado\" : \"Sensor sin evento\";\n  $(\"kpiTemp\").textContent = `${fmt(last.temp, 1)} °C`; $(\"kpiHum\").textContent = `${fmt(last.hum, 1)} %`; $(\"kpiSpeed\").textContent = fmt(last.speed);\n  $(\"lastUpdated\").textContent = fmtDate(last.date); $(\"entryCount\").textContent = `${feeds.length} lecturas`;\n  const levelStats = stats(feeds.map((f) => f.level)); $(\"avgLevel\").textContent = `${fmt(levelStats.avg)} m`; $(\"maxLevel\").textContent = `${fmt(levelStats.max)} m`;\n  const spread = levelStats.max - levelStats.min; $(\"insightTitle\").textContent = state.label === \"Crítico\" ? \"La estación exige atención.\" : spread > 5 ? \"El nivel presenta alta variación.\" : \"La serie se mantiene contenida.\";\n  $(\"insightText\").textContent = `En la ventana analizada, el nivel osciló entre ${fmt(levelStats.min)} y ${fmt(levelStats.max)} m. El estado más reciente es ${state.label.toLowerCase()}.`;\n  renderCharts(); renderTable();\n}\n\nfunction baseChartOptions() { return { animationDuration: 650, textStyle: { fontFamily: \"Manrope\", color: \"#7e9da7\" }, grid: { left: 45, right: 20, top: 34, bottom: 40 }, tooltip: { trigger: \"axis\", backgroundColor: \"#08232d\", borderColor: \"rgba(151,210,222,.2)\", textStyle: { color: \"#dff7fb\", fontSize: 10 } }, xAxis: { type: \"category\", boundaryGap: false, data: feeds.map(f => fmtDate(f.date, true)), axisLine: { lineStyle: { color: \"rgba(151,210,222,.12)\" } }, axisLabel: { color: \"#547681\", fontSize: 8, hideOverlap: true }, axisTick: { show: false } }, yAxis: { type: \"value\", scale: true, splitLine: { lineStyle: { color: \"rgba(151,210,222,.07)\" } }, axisLabel: { color: \"#547681\", fontSize: 8 } } }; }\nfunction lineSeries(name, data, color, area = true) { return { name, type: \"line\", data, smooth: .28, showSymbol: false, connectNulls: true, lineStyle: { width: 2, color }, itemStyle: { color }, areaStyle: area ? { color: { type: \"linear\", x: 0, y: 0, x2: 0, y2: 1, colorStops: [{ offset: 0, color: `${color}55` }, { offset: 1, color: `${color}00` }] } } : undefined }; }\nfunction chart(id, options) { const el = $(id); let instance = echarts.getInstanceByDom(el); if (!instance) { instance = echarts.init(el); charts.push(instance); } instance.setOption(options, true); }\nfunction renderCharts() {\n  chart(\"levelChart\", { ...baseChartOptions(), series: [lineSeries(\"Nivel\", feeds.map(f => f.level), \"#39e1d0\")] });\n  chart(\"predictionChart\", { ...baseChartOptions(), series: [lineSeries(\"Predicción\", feeds.map(f => f.prediction), \"#a984ff\")] });\n  chart(\"speedChart\", { ...baseChartOptions(), series: [lineSeries(\"Velocidad\", feeds.map(f => f.speed), \"#6be6a4\")] });\n  const climate = baseChartOptions(); climate.legend = { data: [\"Temperatura\", \"Humedad\"], textStyle: { color: \"#73939d\", fontSize: 9 }, top: 4 }; climate.yAxis = [{ ...climate.yAxis, name: \"°C\", nameTextStyle: { color: \"#567984\" } }, { ...climate.yAxis, name: \"%\", nameTextStyle: { color: \"#567984\" } }]; climate.series = [lineSeries(\"Temperatura\", feeds.map(f => f.temp), \"#ffad5b\", false), { ...lineSeries(\"Humedad\", feeds.map(f => f.hum), \"#58a6ff\", false), yAxisIndex: 1 }]; chart(\"climateChart\", climate);\n  const events = baseChartOptions(); events.xAxis.boundaryGap = true; events.yAxis = { type: \"value\", min: 0, max: 3, interval: 1, axisLabel: { color: \"#547681\", fontSize: 8, formatter: value => STATUS[value]?.label || value }, splitLine: { lineStyle: { color: \"rgba(151,210,222,.07)\" } } }; events.series = [{ name: \"Estado\", type: \"bar\", data: feeds.map(f => ({ value: f.status, itemStyle: { color: (STATUS[f.status] || STATUS[0]).color, borderRadius: [4,4,0,0] } })), barMaxWidth: 8 }]; chart(\"eventsChart\", events);\n}\nfunction renderTable() { $(\"recordsBody\").innerHTML = [...feeds].reverse().slice(0, 20).map(row => { const state = STATUS[row.status] || { label: `Código ${row.status}`, className: \"\" }; return `<tr><td>${fmtDate(row.date)}</td><td>${fmt(row.level)} m</td><td>${row.rain > 0 ? fmt(row.rain) : \"No\"}</td><td>${fmt(row.temp,1)} °C</td><td>${fmt(row.hum,1)} %</td><td>${fmt(row.speed)}</td><td>${fmt(row.prediction)}</td><td><span class=\"status-chip ${state.className}\">${state.label}</span></td></tr>`; }).join(\"\"); }\nfunction toast(message, error = false) { const el = $(\"toast\"); el.textContent = message; el.style.borderColor = error ? \"rgba(255,107,113,.4)\" : \"\"; el.classList.add(\"show\"); clearTimeout(el._timer); el._timer = setTimeout(() => el.classList.remove(\"show\"), 3200); }\nfunction exportCsv() { const header = [\"fecha_hora\",\"entry_id\",\"nivel\",\"lluvia\",\"temperatura\",\"humedad\",\"velocidad\",\"prediccion\",\"estado\"]; const rows = feeds.map(f => [f.date.toISOString(),f.entryId,f.level,f.rain,f.temp,f.hum,f.speed,f.prediction,f.status]); const csv = [header,...rows].map(row => row.map(v => `\"${v ?? \"\"}\"`).join(\",\")).join(\"\\n\"); const a=document.createElement(\"a\"); a.href=URL.createObjectURL(new Blob([csv],{type:\"text/csv;charset=utf-8\"})); a.download=`thingspeak-${currentConfig().channel}-${new Date().toISOString().slice(0,10)}.csv`; a.click(); URL.revokeObjectURL(a.href); }\n\nif (typeof document !== \"undefined\") {\n  $(\"refreshButton\").addEventListener(\"click\", () => loadData(true)); $(\"rangeSelect\").addEventListener(\"change\", () => loadData()); $(\"downloadCsv\").addEventListener(\"click\", exportCsv);\n  const showSettings = () => { $(\"channelInput\").value=currentConfig().channel; $(\"apiKeyInput\").value=currentConfig().apiKey; $(\"settingsDialog\").showModal(); };\n  $(\"openSettings\").addEventListener(\"click\", showSettings); $(\"mobileSettings\").addEventListener(\"click\", showSettings);\n  $(\"settingsForm\").addEventListener(\"submit\", event => { event.preventDefault(); sessionStorage.setItem(\"tsChannel\", $(\"channelInput\").value.trim()); const key=$(\"apiKeyInput\").value.trim(); key ? sessionStorage.setItem(\"tsReadKey\",key) : sessionStorage.removeItem(\"tsReadKey\"); $(\"settingsDialog\").close(); loadData(true); });\n  window.addEventListener(\"resize\", () => charts.forEach(c => c.resize()));\n  document.querySelectorAll(\".sidebar nav a\").forEach(a => a.addEventListener(\"click\", () => { document.querySelectorAll(\".sidebar nav a\").forEach(n=>n.classList.remove(\"active\")); a.classList.add(\"active\"); }));\n  loadData(); refreshTimer = setInterval(loadData, 20000);\n}\n</script>\n</body>\n</html>\n";
export default {
  async fetch(request) {
    const url = new URL(request.url);
    if (url.pathname !== "/" && url.pathname !== "/index.html") {
      return new Response("No encontrado", { status: 404, headers: { "content-type": "text/plain; charset=utf-8" } });
    }
    return new Response(HTML, {
      headers: {
        "content-type": "text/html; charset=utf-8",
        "cache-control": "public, max-age=300",
        "content-security-policy": "default-src 'self'; script-src 'self' 'unsafe-inline' https://cdn.jsdelivr.net; style-src 'self' 'unsafe-inline' https://fonts.googleapis.com; font-src https://fonts.gstatic.com; connect-src 'self' https://api.thingspeak.com; img-src 'self' data:; object-src 'none'; base-uri 'self'; frame-ancestors 'none'",
        "referrer-policy": "strict-origin-when-cross-origin",
        "x-content-type-options": "nosniff",
      },
    });
  },
};
